def correct_bracketing(brackets: str):
    """return True if every opening bracket has a corresponding closing bracket."""
    depth = 0
    for b in brackets:
        if b == '(':
            depth += 1
        elif b == ')':
            depth -= 1
            if depth < 0:
                return False
    return depth == 0

# Complexity: O(n) time, O(1) space — single pass, constant counter
# Edge cases: empty string (returns True — depth stays 0), closing bracket before any opening (returns False immediately), unmatched opening brackets left over (returns False via depth != 0)
```

